@_documentation(visibility: private)
#endif
public func FfiConverterTypeScanHandle_lower(_ value: ScanHandle) -> UnsafeMutableRawPointer {
    return FfiConverterTypeScanHandle.lower(value)
}




public struct BigFile {
    public var path: String
    public var logicalSize: UInt64
    public var allocatedSize: UInt64
    /**
     * 파일 mtime (unix 초). 0 = 미상.
     */
    public var mtime: Int64

    // Default memberwise initializers are never public by default, so we
    // declare one manually.
    public init(path: String, logicalSize: UInt64, allocatedSize: UInt64, 
        /**
         * 파일 mtime (unix 초). 0 = 미상.
         */mtime: Int64) {
        self.path = path
        self.logicalSize = logicalSize
        self.allocatedSize = allocatedSize
        self.mtime = mtime
    }
}

#if compiler(>=6)
extension BigFile: Sendable {}
#endif


extension BigFile: Equatable, Hashable {
    public static func ==(lhs: BigFile, rhs: BigFile) -> Bool {
        if lhs.path != rhs.path {
            return false
        }
        if lhs.logicalSize != rhs.logicalSize {
            return false
        }
        if lhs.allocatedSize != rhs.allocatedSize {
            return false
        }
        if lhs.mtime != rhs.mtime {
            return false
        }
        return true
    }

    public func hash(into hasher: inout Hasher) {
        hasher.combine(path)
        hasher.combine(logicalSize)
        hasher.combine(allocatedSize)
        hasher.combine(mtime)
    }
}



